from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class XfaDoubleField(XfaField):
    """
    Represents a double field in an XFA form.
    """

    @property
    def Value(self) -> float:
        """
        Gets the value of the double field.
        """
        GetDllLibPdf().spr_pdf_XfaDoubleField_get_Value.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_XfaDoubleField_get_Value.restype = c_double
        ret = CallCFunction(GetDllLibPdf().spr_pdf_XfaDoubleField_get_Value,self.Ptr)
        return ret

    @Value.setter
    def Value(self, value: float):
        """
        Sets the value of the double field.
        """
        GetDllLibPdf().spr_pdf_XfaDoubleField_set_Value.argtypes = [c_void_p, c_double]
        CallCFunction(GetDllLibPdf().spr_pdf_XfaDoubleField_set_Value,self.Ptr, value)